diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 162ebebf1b8f..ce141aa9808a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -1050,7 +1050,25 @@ static Value *canonicalizeSaturatedAdd(ICmpInst *Cmp, Value *TVal, Value *FVal,
       match(FVal, m_c_Add(m_Specific(X), m_Value(Y))) && Y == Cmp1) {
     // (~X u< Y) ? -1 : (X + Y) --> uadd.sat(X, Y)
     // (~X u< Y) ? -1 : (Y + X) --> uadd.sat(X, Y)
-    return Builder.CreateBinaryIntrinsic(Intrinsic::uadd_sat, X, Y);
+    {
+      // Avoid folding if the NOT is an xor with a poison-containing constant.
+      auto HasPoisonNot = [](Value *V) {
+        if (!V) return false;
+        if (auto *BO = dyn_cast<BinaryOperator>(V)) {
+          if (BO->getOpcode() == Instruction::Xor)
+            if (auto *C = dyn_cast<Constant>(BO->getOperand(1)))
+              return C->containsPoisonElement();
+        } else if (auto *CE = dyn_cast<ConstantExpr>(V)) {
+          if (CE->getOpcode() == Instruction::Xor)
+            if (auto *C = dyn_cast<Constant>(CE->getOperand(1)))
+              return C->containsPoisonElement();
+        }
+        return false;
+      };
+      if (HasPoisonNot(Cmp0))
+        return nullptr;
+      return Builder.CreateBinaryIntrinsic(Intrinsic::uadd_sat, X, Y);
+    }
   }
   // The 'not' op may be included in the sum but not the compare.
   // Strictness of the comparison is irrelevant.
@@ -1060,9 +1078,27 @@ static Value *canonicalizeSaturatedAdd(ICmpInst *Cmp, Value *TVal, Value *FVal,
     // (X u< Y) ? -1 : (~X + Y) --> uadd.sat(~X, Y)
     // (X u< Y) ? -1 : (Y + ~X) --> uadd.sat(Y, ~X)
     BinaryOperator *BO = cast<BinaryOperator>(FVal);
+    {
+    // Avoid folding if either operand is a NOT encoded as xor with poison.
+    auto HasPoisonNot = [](Value *V) {
+      if (!V) return false;
+      if (auto *BO2 = dyn_cast<BinaryOperator>(V)) {
+        if (BO2->getOpcode() == Instruction::Xor)
+          if (auto *C = dyn_cast<Constant>(BO2->getOperand(1)))
+            return C->containsPoisonElement();
+      } else if (auto *CE2 = dyn_cast<ConstantExpr>(V)) {
+        if (CE2->getOpcode() == Instruction::Xor)
+          if (auto *C = dyn_cast<Constant>(CE2->getOperand(1)))
+            return C->containsPoisonElement();
+      }
+      return false;
+    };
+    if (HasPoisonNot(BO->getOperand(0)) || HasPoisonNot(BO->getOperand(1)))
+      return nullptr;
     return Builder.CreateBinaryIntrinsic(
         Intrinsic::uadd_sat, BO->getOperand(0), BO->getOperand(1));
   }
+  }
   // The overflow may be detected via the add wrapping round.
   // This is only valid for strict comparison!
   if (Pred == ICmpInst::ICMP_ULT &&

